import React from 'react';

/**
 * A helper component that provides a basic accessible page structure with common landmarks.
 * This component ensures that all content passed to it is contained within appropriate
 * ARIA landmarks, addressing Axe violations like "region" and "landmark-one-main".
 *
 * It includes a header, navigation, main content area, and footer, each wrapped in its
 * respective semantic HTML5 landmark element.
 *
 * @param {object} props
 * @param {React.ReactNode} props.children - The primary content of the page, which will be rendered inside the `<main>` landmark.
 * @param {React.ReactNode} [props.headerContent] - Optional content to be rendered inside the `<header>` landmark. Defaults to a basic heading.
 * @param {React.ReactNode} [props.navContent] - Optional content to be rendered inside the `<nav>` landmark. Defaults to a basic "Skip to main content" link.
 * @param {React.ReactNode} [props.footerContent] - Optional content to be rendered inside the `<footer>` landmark. Defaults to a copyright notice.
 */
const AIAccessibilityHelper = ({ children, headerContent, navContent, footerContent }) => {
  return (
    <>
      <header>
        {headerContent || <h1>Welcome to the Application</h1>}
      </header>

      <nav aria-label="Main site navigation">
        {navContent || (
          <ul>
            <li><a href="#main-content">Skip to main content</a></li>
            {/* Add more default navigation links here if desired */}
            <li><a href="/">Home</a></li>
            <li><a href="/about">About</a></li>
          </ul>
        )}
      </nav>

      {/* The main landmark is crucial for the "landmark-one-main" fix */}
      <main id="main-content">
        {children}
      </main>

      <footer>
        {footerContent || <p>&copy; {new Date().getFullYear()} My Accessible App</p>}
      </footer>
    </>
  );
};

export default AIAccessibilityHelper;

